    "q422": {
      "subject": "税法一",
      "chapter": "第七章 车辆购置税",
      "number": 422,
      "type": "single",
      "question": "依据现行车辆购置税的有关规定，下列说法中正确的是（ ）。",
      "options": [
        {
          "letter": "A",
          "text": "车辆购置税实行统一比例税率10%"
        },
        {
          "letter": "B",
          "text": "车辆购置税的纳税人不包括外商投资企业"
        },
        {
          "letter": "C",
          "text": "自产自用应税车辆的单位，不需要缴纳车辆购置税"
        },
        {
          "letter": "D",
          "text": "城市公交企业购置的公共汽电车辆，需要缴纳车辆购置税"
        }
      ],
      "answer": "A",
      "explanation": "选项B，外商投资企业也属于我国车辆购置税纳税人范围；选项C，自产自用应税车辆是指纳税人将自己生产的应税车辆作为最终消费品用于自己消费使用，需要缴纳车辆购置税；选项D，城市公交企业购置的公共汽电车辆免征车辆购置税。"
    },
    "q423": {
      "subject": "税法一",
      "chapter": "第七章 车辆购置税",
      "number": 423,
      "type": "single",
      "question": "根据车辆购置税相关规定，下列车辆中属于车辆购置税征税对象的是（ ）。",
      "options": [
        {
          "letter": "A",
          "text": "新能源汽车"
        },
        {
          "letter": "B",
          "text": "挖掘机"
        },
        {
          "letter": "C",
          "text": "电动摩托车"
        },
        {
          "letter": "D",
          "text": "地铁"
        }
      ],
      "answer": "A",
      "explanation": "地铁、轻轨等城市轨道交通车辆，装载机、平地机、挖掘机、推土机等轮式专用机械车，以及起重机（吊车）、叉车、电动摩托车，不属于应税车辆。新能源汽车虽然有减免税优惠政策，但仍属于车辆购置税的征税范围。"
    },
